import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Plus, TrendingUp, TrendingDown, Wallet, Edit } from 'lucide-react';
import { expenseAPI } from '../utils/api';
import ExpenseChart from '../components/Charts/ExpenseChart';
import QuickStats from '../components/Dashboard/QuickStats';
import RecentExpenses from '../components/Dashboard/RecentExpenses';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { user, setSalary } = useAuth();
  const [stats, setStats] = useState({
    totalSpent: 0,
    expensesThisMonth: 0,
    topCategory: ''
  });
  const [recentExpenses, setRecentExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingSalary, setEditingSalary] = useState(false);
  const [newSalary, setNewSalary] = useState(user?.salary || '');

  useEffect(() => {
    loadDashboardData();
  }, []);

  const loadDashboardData = async () => {
    try {
      const [expensesData, statsData] = await Promise.all([
        expenseAPI.getRecent(),
        expenseAPI.getDashboardStats()
      ]);
      setRecentExpenses(expensesData);
      setStats(statsData);
    } catch (error) {
      console.error('Error loading dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSalarySave = () => {
    const salaryAmount = parseFloat(newSalary);
    if (!isNaN(salaryAmount) && salaryAmount > 0) {
      setSalary(salaryAmount);
      setEditingSalary(false);
    }
  };

  const remainingBudget = user?.salary ? user.salary - stats.totalSpent : null;
  const overBudget = remainingBudget !== null && remainingBudget < 0;

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div className="dashboard">
      <div className="page-header">
        <h1>Dashboard Overview</h1>
        <Link to="/expenses?action=add" className="btn btn-primary">
          <Plus size={20} />
          Add Expense
        </Link>
      </div>

      <div className="salary-section">
        {user?.salary && !editingSalary ? (
          <div>
            <span>Monthly Salary: ${user.salary.toFixed(2)}</span>
            <button
              className="btn btn-secondary"
              onClick={() => setEditingSalary(true)}
              style={{ marginLeft: '10px' }}
            >
              <Edit size={16} /> Edit
            </button>
          </div>
        ) : (
          <div>
            <input
              type="number"
              placeholder="Enter monthly salary"
              value={newSalary}
              onChange={(e) => setNewSalary(e.target.value)}
            />
            <button className="btn btn-primary" onClick={handleSalarySave}>
              Save
            </button>
          </div>
        )}
      </div>

      <QuickStats stats={{ ...stats, monthlySalary: user?.salary, remainingBudget }} />

      {overBudget && (
        <div className="alert alert-danger">
          Warning: You are over your budget by ${Math.abs(remainingBudget).toFixed(2)}!
        </div>
      )}

      <div className="dashboard-grid">
        <div className="chart-section">
          <h2>Spending Overview</h2>
          <ExpenseChart />
        </div>

        <div className="recent-section">
          <h2>Recent Expenses</h2>
          <RecentExpenses expenses={recentExpenses} />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
